<script setup>import{ref}from'vue';import PageActions from'../../../components/admin/PageActions.vue';import WorkSummaryCards from'../../../components/admin/WorkSummaryCards.vue';import{reportApi}from'../../../lib/reportApi.js';const userId=ref(''),summary=ref(null),error=ref('');async function search(){try{summary.value=await reportApi.collectors({userId:userId.value})}catch(e){error.value=e.message}}</script>
<template><section class="admin-page"><PageActions title="采集员统计" description="按系统用户 ID 查询累计提交、当前有效、释放和废弃。"/><div class="business-card"><form class="business-inline" @submit.prevent="search"><input v-model.trim="userId" required placeholder="采集员用户 ID"/><button class="button-primary">查询</button></form><p v-if="error" class="business-error">{{error}}</p><WorkSummaryCards v-if="summary" :summary="summary.summary||summary"/></div></section></template>
